    ctx.registerRoute({
      path: "/plans/:id",
      method: "PUT",
      description: "Update a content Plan",
      handler: async (req) => {
        const url2 = new URL(req.url);
        const body = await readBody(req);
        const id = url2.searchParams.get("id") || body.id;
        if (!id)
          return json3({ error: "id required" }, 400);
        try {
          const channelsProvided = Object.prototype.hasOwnProperty.call(body, "channels");
          const existing = contentStore.getPlan(id);
          if (!existing)
            return json3({ error: "Plan not found" }, 404);
          if (channelsProvided && hasLinkedPlanWork(contentStore, id)) {
            return json3({ error: "Plan channels are locked after activation; delete individual channels instead" }, 409);
          }
          const plan = contentStore.updatePlan(id, {
            title: body.title,
            brief: body.brief,
            targetDate: body.targetDate,
            agent: body.agent,
            status: body.status,
            campaign: body.campaign,
            channels: channelsProvided ? normalizePlanChannels(body.channels) : undefined
          });
          ctx.activity.audit("plan.updated", "system", { planId: id });
          return json3({ ok: true, plan });
        } catch (err) {
          return json3({ error: err instanceof Error ? err.message : String(err) }, 404);
        }
      }
    });
