    ctx.registerRoute({
      path: "/deliverables",
      method: "POST",
      description: "Create a Quick Post Deliverable. Plan Deliverables are created only by Plan activation.",
      handler: async (req) => {
        const body = await readBody(req);
        if (!body.title || !body.brief || !body.channel || !body.contentType || !body.tone || !body.agent || !body.publishAt) {
          return json3({ error: "title, brief, channel, contentType, tone, agent, and publishAt required" }, 400);
        }
        const planId = parseNullablePlanId(body.planId) ?? null;
        if (planId && !contentStore.getPlan(planId))
          return json3({ error: "Plan not found" }, 404);
        if (planId)
          return json3({ error: PLAN_DELIVERABLE_CREATION_ERROR }, 409);
        try {
          const contentType = body.contentType;
          const publishAt = body.publishAt;
          const deliverable = contentStore.createDeliverable({
            planId,
            channel: body.channel,
            contentType,
            tone: body.tone,
            agent: body.agent,
            title: body.title,
            brief: body.brief,
            publishAt,
            prepStartAt: body.prepStartAt ?? derivePrepStartAt2(ctx, publishAt, contentType),
            prepStartAtOverride: body.prepStartAtOverride,
            status: body.status ?? "planned",
            draft: parseDraft(body.draft)
          });
          recomputeLinkedPlan2(contentStore, planId);
          ctx.activity.audit("deliverable.created", body.agent, { deliverableId: deliverable.id, planId });
          ctx.activity.log(body.agent, `Created content Deliverable "${deliverable.title}"`);
          return json3({ ok: true, deliverable });
        } catch (err) {
          return json3({ error: err instanceof Error ? err.message : String(err) }, 400);
        }
      }
    });
    ctx.registerRoute({
      path: "/deliverables/:id",
      method: "PUT",
      description: "Update a content Deliverable",
      handler: async (req) => {
        const url2 = new URL(req.url);
        const body = await readBody(req);
        const id = url2.searchParams.get("id") || body.id;
        if (!id)
          return json3({ error: "id required" }, 400);
        const existing = contentStore.getDeliverable(id);
        if (!existing)
          return json3({ error: "Deliverable not found" }, 404);
        const planId = parseNullablePlanId(body.planId);
        if (planId && !contentStore.getPlan(planId))
          return json3({ error: "Plan not found" }, 404);
        if (planId && planId !== existing.planId)
          return json3({ error: PLAN_DELIVERABLE_CREATION_ERROR }, 409);
        const contentType = body.contentType;
        const publishAt = body.publishAt;
        const shouldDerivePrepStartAt = !body.prepStartAt && (contentType || publishAt);
        try {
          const deliverable = contentStore.updateDeliverable(id, {
            planId,
            channel: body.channel,
            contentType,
            tone: body.tone,
            agent: body.agent,
            title: body.title,
            brief: body.brief,
            publishAt,
            prepStartAt: body.prepStartAt ?? (shouldDerivePrepStartAt ? derivePrepStartAt2(ctx, publishAt ?? existing.publishAt, contentType ?? existing.contentType) : undefined),
            prepStartAtOverride: body.prepStartAtOverride,
            status: body.status,
            draft: parseDraft(body.draft),
            rejectionNote: body.rejectionNote
          });
          recomputeLinkedPlan2(contentStore, existing.planId);
          if (deliverable.planId !== existing.planId)
            recomputeLinkedPlan2(contentStore, deliverable.planId);
          ctx.activity.audit("deliverable.updated", "system", { deliverableId: id, planId: deliverable.planId });
          return json3({ ok: true, deliverable });
        } catch (err) {
          return json3({ error: err instanceof Error ? err.message : String(err) }, 400);
        }
      }
    });
