    ctx.registerExecTool({
      name: "bakin_exec_messaging_deliverable_list",
      label: "Listed content deliverables",
      description: "List content Deliverables with optional filters",
      parameters: {
        planId: exports_external.union([exports_external.string(), exports_external.null()]).optional().describe("Filter by Plan ID; null returns Quick Posts"),
        status: exports_external.string().optional().describe("Filter by Deliverable status"),
        channel: exports_external.string().optional().describe("Filter by channel"),
        publishAfter: exports_external.string().optional().describe("Filter by publishAt at or after this date"),
        publishBefore: exports_external.string().optional().describe("Filter by publishAt at or before this date")
      },
      handler: async (params) => {
        let deliverables = contentStore.listDeliverables();
        const planId = parseNullablePlanId(params.planId);
        if (planId !== undefined)
          deliverables = deliverables.filter((deliverable) => deliverable.planId === planId);
        if (params.status)
          deliverables = deliverables.filter((deliverable) => deliverable.status === params.status);
        if (params.channel)
          deliverables = deliverables.filter((deliverable) => deliverable.channel === params.channel);
        if (params.publishAfter)
          deliverables = deliverables.filter((deliverable) => Date.parse(deliverable.publishAt) >= Date.parse(params.publishAfter));
        if (params.publishBefore)
          deliverables = deliverables.filter((deliverable) => Date.parse(deliverable.publishAt) <= Date.parse(params.publishBefore));
        return { ok: true, count: deliverables.length, deliverables };
      }
    });
