      activityDuplicate: true,
      description: "Update a content Deliverable. Draft fields are deep-merged.",
      parameters: {
        deliverableId: exports_external.string().describe("Deliverable ID (required)"),
        planId: exports_external.union([exports_external.string(), exports_external.null()]).optional().describe("Optional Plan ID; null makes it a Quick Post"),
        channel: exports_external.string().optional().describe("Runtime channel ID"),
        contentType: exports_external.string().optional().describe("Messaging content type ID"),
        tone: exports_external.string().optional().describe("Tone"),
        agent: exports_external.string().optional().describe("Prep agent"),
        title: exports_external.string().optional().describe("Deliverable title"),
        brief: exports_external.string().optional().describe("Deliverable brief"),
        publishAt: exports_external.string().optional().describe("Publish datetime"),
        prepStartAt: exports_external.string().optional().describe("Optional explicit prep start datetime"),
        prepStartAtOverride: exports_external.string().optional().describe("Optional prep start override datetime"),
        status: exports_external.string().optional().describe("Deliverable status"),
        rejectionNote: exports_external.string().optional().describe("Optional rejection note"),
        draft: exports_external.object({}).passthrough().optional().describe("Draft fields to deep-merge")
      },
      handler: async (params) => {
        if (!params.deliverableId)
          return { ok: false, error: "deliverableId required" };
        if (params.status)
          return { ok: false, status: 403, error: AGENT_DELIVERABLE_STATUS_ERROR };
        const id = params.deliverableId;
        const existing = contentStore.getDeliverable(id);
        if (!existing)
          return { ok: false, error: "Deliverable not found" };
        const planId = parseNullablePlanId(params.planId);
        if (planId && !contentStore.getPlan(planId))
          return { ok: false, error: "Plan not found" };
        if (planId && planId !== existing.planId)
          return { ok: false, error: PLAN_DELIVERABLE_CREATION_ERROR };
        const contentType = params.contentType;
        const publishAt = params.publishAt;
        const shouldDerivePrepStartAt = !params.prepStartAt && (contentType || publishAt);
        try {
          const deliverable = contentStore.updateDeliverable(id, {
            planId,
            channel: params.channel,
            contentType,
            tone: params.tone,
            agent: params.agent,
            title: params.title,
            brief: params.brief,
            publishAt,
            prepStartAt: params.prepStartAt ?? (shouldDerivePrepStartAt ? derivePrepStartAt2(ctx, publishAt ?? existing.publishAt, contentType ?? existing.contentType) : undefined),
            prepStartAtOverride: params.prepStartAtOverride,
            status: params.status,
            draft: parseDraft(params.draft),
            rejectionNote: params.rejectionNote
          });
          recomputeLinkedPlan2(contentStore, existing.planId);
          if (deliverable.planId !== existing.planId)
            recomputeLinkedPlan2(contentStore, deliverable.planId);
          ctx.activity.audit("deliverable.updated", "system", { deliverableId: id, planId: deliverable.planId });
          return { ok: true, deliverable };
        } catch (err) {
          return { ok: false, error: err instanceof Error ? err.message : String(err) };
        }
      }
