    ctx.registerExecTool({
      name: "bakin_exec_messaging_session_message",
      label: "Sent brainstorm message",
      description: "Send a message in a planning session (non-streaming, returns full response)",
      parameters: {
        sessionId: exports_external.string().describe("Session ID (required)"),
        message: exports_external.string().describe("User message content (required)")
      },
      handler: async (params) => {
        if (!params.sessionId || !params.message)
          return { ok: false, error: "sessionId and message required" };
        const session = contentStore.getBrainstormSession(params.sessionId);
        if (!session)
          return { ok: false, error: "Session not found" };
        if (session.status === "archived")
          return { ok: false, error: "Session is archived" };
        const userMsg = appendBrainstormMessage(contentStore, params.sessionId, {
          role: "user",
          content: params.message
        });
        const promptOptions = await resolvePromptOptions(ctx, session.agentId);
        const messages = buildMessages(session, params.message, promptOptions);
        const sessionKey2 = brainstormThreadId("messaging", params.sessionId, session.agentId);
        let fullContent;
        try {
          fullContent = await sendRuntimeChatCompletion(ctx, {
            messages,
            agentId: session.agentId,
            sessionKey: sessionKey2
          });
        } catch (err) {
          return { ok: false, error: err instanceof Error ? err.message : String(err) };
        }
        const proposals = [];
        const blockRegex = /```json\s*([\s\S]*?)\s*```/g;
        let match;
        while ((match = blockRegex.exec(fullContent)) !== null) {
          try {
            const parsed = JSON.parse(match[1]);
            proposals.push(...Array.isArray(parsed) ? parsed : [parsed]);
          } catch {}
        }
        const cleanContent = fullContent.replace(/```json[\s\S]*?```/g, "").trim();
        const assistantMsg = appendBrainstormMessage(contentStore, params.sessionId, {
          role: "assistant",
          content: cleanContent
        });
        let savedProposals = [];
        if (proposals.length > 0) {
          savedProposals = upsertBrainstormProposals(contentStore, params.sessionId, assistantMsg.id, proposals);
        }
        return {
          ok: true,
          response: cleanContent,
          messageId: assistantMsg.id,
          userMessageId: userMsg.id,
          proposals: savedProposals
        };
      }
    });
